-- ----------------------------------------------------------------------------
-- vw_workflows: Table: Workflows
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_workflows WITH (security_invoker = ON) AS
SELECT
  t.workflow_id,
  calc_workflows_name(t.workflow_id) AS name,                                   -- Short machine-friendly name for the workflow. Used for programmatic reference and URL slug generation.
  t.display_name,
  t.title,                                                                      -- Human-readable title of the workflow. Maps to dct:title from Dublin Core. Example: 'Production Deployment Workflow', 'Employee Onboarding'.
  t.description,                                                                -- Detailed description of the workflow's purpose and scope. Maps to dct:description from Dublin Core. Should explain what business goal the workflow achieves.
  t.identifier,                                                                 -- External system identifier for cross-referencing. Maps to dct:identifier from Dublin Core. This is the join key back to document management systems, ticket systems, or other operational systems.
  t.modified,                                                                   -- Last modification timestamp. Maps to dct:modified from Dublin Core. Critical for answering CQ5: 'Which workflows haven't been reviewed or updated in twelve months?'
  calc_workflows_workflow_steps(t.workflow_id) AS workflow_steps,               -- Reference to workflow steps. Represents the ntwf:hasStep relationship linking workflows to their constituent steps.
  calc_workflows_count_of_non_proposed_steps(t.workflow_id) AS count_of_non_proposed_steps,-- Calculated count of workflow steps in this workflow. Useful for workflow complexity analysis and reporting.
  calc_workflows_has_more_than1_step(t.workflow_id) AS has_more_than1_step
FROM workflows t;

-- ----------------------------------------------------------------------------
-- vw_workflow_steps: Table: WorkflowSteps
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_workflow_steps WITH (security_invoker = ON) AS
SELECT
  t.workflow_step_id,
  calc_workflow_steps_name(t.workflow_step_id) AS name,
  t.display_name,
  t.workflow,                                                                   -- Foreign key to the parent workflow. Represents the inverse of ntwf:hasStep, enabling navigation from step to its containing workflow (ntwf:isStepOf).
  t.sequence_position,                                                          -- Integer ordinal position of the step within its workflow. Maps to ntwf:sequencePosition, declared as owl:FunctionalProperty (each step has exactly one position). Enables positional queries.
  t.assigned_role,                                                              -- Foreign key to the Role responsible for executing this step. Maps to ntwf:assignedRole. Critical for implementing Heuristic 2 (role-agent separation): steps point to roles, not directly to agents.
  t.requires_human_approval,                                                    -- Boolean flag indicating whether a human agent must fill the assigned role. Maps to ntwf:requiresHumanApproval. Enables answering CQ3: 'Which steps require human decisions vs. AI execution?'
  t.approval_gate,                                                              -- Foreign key to ApprovalGate if this step is a decision checkpoint. When populated, indicates this step blocks workflow execution until explicit authorization is given.
  t.preceded_by_steps                                                           -- Reference to steps that must complete before this step can execute. Part of the ntwf:precedesStep transitive ordering relationship.
FROM workflow_steps t;

-- ----------------------------------------------------------------------------
-- vw_approval_gates: Table: ApprovalGates
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_approval_gates WITH (security_invoker = ON) AS
SELECT
  t.approval_gate_id,
  calc_approval_gates_name(t.approval_gate_id) AS name,
  t.display_name,
  calc_approval_gates_workflow_steps(t.approval_gate_id) AS workflow_steps,     -- Back-reference to workflow steps that use this approval gate. Enables finding all steps requiring this specific gate.
  t.escalation_threshold_hours                                                  -- Integer number of hours that may elapse on a pending gate before the ntwf:delegatesTo chain activates. Maps to ntwf:escalationThresholdHours. Domain applies only to ApprovalGate individuals.
FROM approval_gates t;

-- ----------------------------------------------------------------------------
-- vw_precedes_steps: Table: PrecedesSteps
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_precedes_steps WITH (security_invoker = ON) AS
SELECT
  t.precedes_step_id,
  t.name,                                                                       -- Ordinal sequence number for the relationship. Used for sorting and display.
  t.workflow_step,                                                              -- Foreign key to the step that comes BEFORE. The source of the 'precedes' relationship.
  calc_precedes_steps_display_name(t.precedes_step_id) AS display_name,
  t.step_number
FROM precedes_steps t;

-- ----------------------------------------------------------------------------
-- vw_roles: Table: Roles
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,
  calc_roles_name(t.role_id) AS name,
  t.display_name,
  t.label,                                                                      -- Human-readable display name. Maps to rdfs:label. Per Heuristic 6: if you cannot write a clear label, you do not yet understand the concept well enough to model it.
  t.comment,                                                                    -- Detailed description of the role's responsibilities and scope. Maps to rdfs:comment. Should define what the role covers, what it excludes, and how it differs from adjacent roles.
  t.filled_by_human_agent,
  t.filled_by_ai_agent,
  t.filled_by_automated_pipeline,
  t.owned_by,                                                                   -- Foreign key to the Department that owns this role. Maps to ntwf:ownedBy (owl:FunctionalProperty). Enables answering CQ7: 'Which workflows involve both Engineering and Legal?'
  t.delegates_to,                                                               -- Foreign key to the next Role in the escalation chain. Maps to ntwf:delegatesTo. Enables answering CQ6: 'What happens when the VP of Engineering is unavailable?'
  calc_roles_workflow_steps(t.role_id) AS workflow_steps,                       -- Back-reference to workflow steps assigned to this role. Inverse of WorkflowSteps.AssignedRole.
  t.from_delegates_to
FROM roles t;

-- ----------------------------------------------------------------------------
-- vw_departments: Table: Departments
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_departments WITH (security_invoker = ON) AS
SELECT
  t.department_id,
  calc_departments_name(t.department_id) AS name,                               -- Human-readable display name of the department. Should match organizational terminology for stakeholder communication.
  t.title,                                                                      -- Human-readable display name of the department. Should match organizational terminology for stakeholder communication.
  t.display_name,                                                               -- Machine-friendly name for programmatic reference.
  t.roles                                                                       -- Back-reference to roles owned by this department. Inverse of Roles.OwnedBy.
FROM departments t;

-- ----------------------------------------------------------------------------
-- vw_human_agents: Table: HumanAgents
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_human_agents WITH (security_invoker = ON) AS
SELECT
  t.human_agent_id,
  t.name,                                                                       -- Full name of the person. Maps to foaf:name. Note: FOAF's name property is appropriate for persons, not for software systems (which use schema:name).
  t.display_name,
  t.mbox,                                                                       -- Email address of the person. Maps to foaf:mbox. Used for notifications and organizational directory integration.
  t.roles                                                                       -- Back-reference to roles currently filled by this agent. Inverse of Roles.FilledBy_HumanAgent.
FROM human_agents t;

-- ----------------------------------------------------------------------------
-- vw_ai_agents: Table: AIAgents
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_ai_agents WITH (security_invoker = ON) AS
SELECT
  t.ai_agent_id,
  t.name,                                                                       -- Display name of the AI agent. Maps to schema:name (not foaf:name, which is for persons).
  t.title,
  t.display_name,
  t.model_version,                                                              -- Version string of the AI model. Maps to ntwf:modelVersion. Makes AI-produced artifacts auditable at the version level. The domain declaration means this property applies only to AIAgent individuals.
  t.roles                                                                       -- Back-reference to roles currently filled by this AI agent. Inverse of Roles.FilledBy_AIAgent.
FROM ai_agents t;

-- ----------------------------------------------------------------------------
-- vw_automated_pipelines: Table: AutomatedPipelines
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_automated_pipelines WITH (security_invoker = ON) AS
SELECT
  t.automated_pipeline_id,
  t.name,                                                                       -- Display name of the pipeline. Maps to schema:name (appropriate for software systems, unlike foaf:name which is for persons).
  t.description,
  t.display_name,
  t.roles                                                                       -- Back-reference to roles currently filled by this pipeline. Inverse of Roles.FilledBy_AutomatedPipeline.
FROM automated_pipelines t;

